import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { usePrograms } from '@/context/ProgramsContext';
import ProgramModal from './ProgramModal';
import CreateNewProgram from './CreateNewProgram';
import { getAuth, signOut } from 'firebase/auth';
import { auth as firebaseAuth } from '@/services/firebase/config';
import { Program } from '@/types/program';
import { ErrorBoundary } from '@/components/ErrorBoundary';
import { TrashIcon, PlusIcon, DuplicateIcon } from '@heroicons/react/outline';
import SideMenu from '@/components/SideMenu';

const ProgramListContent: React.FC<{ onSelect?: (id: string) => void }> = ({ onSelect }) => {
  const navigate = useNavigate();
  const { programs, addProgram: create, refresh, deleteProgram, duplicateProgram } = usePrograms();
  const [showModal, setShowModal] = useState(false);
  const [showCreateNew, setShowCreateNew] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [deletingProgramId, setDeletingProgramId] = useState<string | null>(null);
  const [duplicatingProgramId, setDuplicatingProgramId] = useState<string | null>(null);
  const [showSideMenu, setShowSideMenu] = useState(false);
  const auth = getAuth();

  // No need for useEffect to refresh - ProgramsContext handles this automatically

  const handleAdd = async (data: { name: string; description: string }) => {
    setError(null);
    const user = auth.currentUser;
    if (!user) {
      setError('You must be logged in to create a program');
      return;
    }

    // Create program without fields that will be generated by backend
    const newProgram = {
      name: data.name,
      description: data.description || '',
      createdBy: user.uid,
      sessions: [],
      isPublic: false,
      tags: [],
      // Backend will generate these fields
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    } as Omit<Program, 'id' | 'userId'>;

    console.log('[ProgramList] Creating new program:', newProgram);
    
    try {
      await create(newProgram);
      console.log('[ProgramList] Program created successfully');
      setShowModal(false);
      // Wait for programs to refresh and get the new program
      await refresh();
      // Find the newly created program
      const createdProgram = programs.find(p => 
        p.name === data.name && 
        p.userId === user.uid &&
        p.createdBy === user.uid
      );
      if (createdProgram) {
        navigate(`/programs/${createdProgram.id}`);
      } else {
        // If we can't find it immediately, just stay on programs list
        console.log('[ProgramList] Created program not found in list, staying on programs page');
      }
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to create program';
      console.error('[ProgramList] Error in handleAdd:', err);
      setError(errorMessage);
    }
  };

  const handleCreateNewSave = async (program: Omit<Program, 'id' | 'userId'>) => {
    try {
      console.log('[ProgramList] Creating new program:', program);
      await create(program);
      setShowCreateNew(false);
      await refresh();
      
      // Navigate to the newly created program
      const createdProgram = programs.find(p => 
        p.name === program.name && 
        p.userId === auth.currentUser?.uid &&
        p.createdBy === auth.currentUser?.uid
      );
      if (createdProgram) {
        navigate(`/programs/${createdProgram.id}`);
      }
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to create program';
      console.error('Error creating program:', err);
      setError(errorMessage);
    }
  };

  const handleDeleteProgram = async (programId: string, programName: string, event: React.MouseEvent) => {
    event.stopPropagation(); // Prevent card click navigation
    
    if (window.confirm(`Are you sure you want to delete the program "${programName}"? This action cannot be undone.`)) {
      setDeletingProgramId(programId);
      setError(null);
      
      try {
        console.log('[ProgramList] Deleting program:', programId);
        await deleteProgram(programId);
        console.log('[ProgramList] Program deleted successfully');
        // Refresh the programs list
        await refresh();
      } catch (err) {
        const errorMessage = err instanceof Error ? err.message : 'Failed to delete program';
        console.error('[ProgramList] Error deleting program:', err);
        setError(errorMessage);
      } finally {
        setDeletingProgramId(null);
      }
    }
  };

  const handleDuplicateProgram = async (programId: string, _programName: string, event: React.MouseEvent) => {
    event.stopPropagation(); // Prevent card click navigation
    
    setDuplicatingProgramId(programId);
    setError(null);
    
    try {
      console.log('[ProgramList] Duplicating program:', programId);
      const duplicatedProgram = await duplicateProgram(programId);
      console.log('[ProgramList] Program duplicated successfully:', duplicatedProgram.id);
      // Navigate to the duplicated program
      navigate(`/programs/${duplicatedProgram.id}`);
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to duplicate program';
      console.error('[ProgramList] Error duplicating program:', err);
      setError(errorMessage);
    } finally {
      setDuplicatingProgramId(null);
    }
  };

  const handleLogout = async () => {
    try {
      await signOut(firebaseAuth);
      navigate('/login');
    } catch (error) {
      console.error('Logout error:', error);
    }
  };

  return (
    <div className="fixed inset-0 bg-bg-primary flex flex-col z-40">
      {/* Header */}
      <header className="bg-bg-secondary border-b border-border p-4 flex-shrink-0">
        <div className="flex items-center justify-between gap-3 flex-wrap">
          <div className="flex items-center gap-3">
            <button 
              onClick={() => setShowSideMenu(true)}
              className="p-1 hover:bg-hover-overlay rounded-lg transition-colors"
              aria-label="Open Menu"
            >
              <svg className="w-6 h-6 text-text-tertiary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>
            <h2 className="text-xl font-semibold text-text-primary">Programs</h2>
          </div>
          <div className="flex items-center gap-2">
            <button
              onClick={() => navigate('/teams?tab=programs')}
              className="px-4 py-2.5 bg-bg-tertiary text-text-primary rounded-xl hover:bg-bg-quaternary transition-all duration-200 flex items-center gap-2 font-medium shadow-lg"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" />
              </svg>
              <span className="hidden sm:inline">Assigned</span>
            </button>
            <button
              onClick={() => setShowCreateNew(true)}
              className="px-4 py-2.5 bg-accent-primary text-text-inverse rounded-xl hover:bg-accent-hover transition-all duration-200 flex items-center gap-2 font-medium shadow-lg"
            >
              <PlusIcon className="w-4 h-4" />
              Create Program
            </button>
            <button
              onClick={handleLogout}
              className="px-3 py-2 bg-red-600 hover:bg-red-700 text-text-primary rounded-lg transition-colors"
            >
              Logout
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-4 min-h-0">
        <div className="max-w-7xl mx-auto">
      {error && (
        <div className="mb-4 p-4 bg-red-500/10 border border-red-500/20 text-red-400 rounded-xl">
          {error}
        </div>
      )}
      {programs.length === 0 ? (
        <div className="text-center py-16">
          <div className="w-20 h-20 mx-auto mb-6 rounded-2xl bg-bg-tertiary/50 flex items-center justify-center">
            <svg className="w-10 h-10 text-text-tertiary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
            </svg>
          </div>
          <h3 className="text-xl font-medium text-text-primary mb-3">No programs yet</h3>
          <p className="text-text-tertiary text-sm mb-8">Create your first training program to get started</p>
          <button
            onClick={() => setShowCreateNew(true)}
            className="px-6 py-3 bg-accent-primary text-text-inverse rounded-xl hover:bg-accent-hover transition-all duration-200 font-medium shadow-lg"
          >
            Create Program
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {programs.map((program: Program) => (
            <div
              key={program.id}
              className="relative bg-bg-secondary rounded-2xl p-5 flex flex-col justify-between min-h-[140px] cursor-pointer overflow-hidden group border border-border hover:border-border-hover transition-all duration-200 hover:shadow-xl"
              onClick={() => (onSelect ? onSelect(program.id) : navigate(`/programs/${program.id}`))}
            >
              <div className="absolute right-4 top-4 opacity-10 text-4xl pointer-events-none select-none">
                <span role="img" aria-label="kettlebell">🏋️‍♂️</span>
              </div>
              
              {/* Action buttons */}
              <div className="absolute top-3 left-3 flex gap-2 opacity-0 group-hover:opacity-100 transition-all duration-200 z-20">
                <button
                  onClick={(e) => handleDuplicateProgram(program.id, program.name, e)}
                  disabled={duplicatingProgramId === program.id}
                  className="p-2 bg-blue-600/90 hover:bg-blue-500 text-text-primary rounded-xl transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed"
                  title="Duplicate program"
                  aria-label={`Duplicate program ${program.name}`}
                >
                  {duplicatingProgramId === program.id ? (
                    <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                  ) : (
                    <DuplicateIcon className="w-4 h-4" />
                  )}
                </button>
                <button
                  onClick={(e) => handleDeleteProgram(program.id, program.name, e)}
                  disabled={deletingProgramId === program.id}
                  className="p-2 bg-red-600/90 hover:bg-red-500 text-text-primary rounded-xl transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed"
                  title="Delete program"
                  aria-label={`Delete program ${program.name}`}
                >
                  {deletingProgramId === program.id ? (
                    <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                  ) : (
                    <TrashIcon className="w-4 h-4" />
                  )}
                </button>
              </div>

              <div className="flex flex-col justify-between h-full z-10">
                <div>
                  <h3 className="font-semibold text-lg text-text-primary mb-2">{program.name}</h3>
                  {program.description && (
                    <p className="text-sm text-text-tertiary mb-3 line-clamp-2">{program.description}</p>
                  )}
                </div>
                
                <div className="flex items-center justify-between">
                  {program.sessions && program.sessions.length > 0 && (
                    <span className="text-text-tertiary text-xs font-medium">
                      {program.sessions.length} session{program.sessions.length !== 1 ? 's' : ''}
                    </span>
                  )}
                </div>
              </div>
              {program.description && (
                <div className="text-text-tertiary text-xs mt-2 z-10 line-clamp-2">{program.description}</div>
              )}
            </div>
          ))}
        </div>
      )}
      <button
        className="fixed bottom-app-floating right-6 bg-accent-primary hover:bg-accent-hover text-text-inverse rounded-full w-14 h-14 flex items-center justify-center text-3xl shadow-lg z-50"
        onClick={() => setShowModal(true)}
        aria-label="Add Program"
      >
        +
      </button>
        </div>
      </main>
      
      <ProgramModal 
        isOpen={showModal} 
        onClose={() => {
          setShowModal(false);
          setError(null);
        }} 
        onSave={handleAdd} 
      />
      
      {showCreateNew && (
        <CreateNewProgram
          onClose={() => setShowCreateNew(false)}
          onSave={handleCreateNewSave}
        />
      )}

      {/* Side Menu */}
      <SideMenu
        isOpen={showSideMenu}
        onClose={() => setShowSideMenu(false)}
        onNavigateToday={() => navigate('/')}
        onOpenProfile={() => navigate('/profile')}
      />
    </div>
  );
};

const ProgramList: React.FC<{ onSelect?: (id: string) => void }> = (props) => {
  return (
    <ErrorBoundary fallback={<div className="text-text-primary p-4">Error loading programs. Please try again.</div>}>
      <ProgramListContent {...props} />
    </ErrorBoundary>
  );
};

export default ProgramList;

